workbox_routing_registerRoute(/^https:\/\/fonts\.(googleapis|gstatic)\.com\/.*/i, new workbox_strategies_CacheFirst({ "cacheName":"google-fonts", plugins: [new workbox_expiration_ExpirationPlugin({ maxEntries: 20, maxAgeSeconds: 2592000 })] }), 'GET');
workbox_routing_registerRoute(/^https:\/\/[^/]+\/api\/.*/i, new workbox_strategies_NetworkFirst({ "cacheName":"api-cache","networkTimeoutSeconds":10, plugins: [new workbox_expiration_ExpirationPlugin({ maxEntries: 100, maxAgeSeconds: 86400 })] }), 'GET');
workbox_routing_registerRoute(/^https:\/\/[^/]+\/((?!api\/).)*$/i, new workbox_strategies_NetworkFirst({ "cacheName":"pages-cache","networkTimeoutSeconds":10, plugins: [new workbox_expiration_ExpirationPlugin({ maxEntries: 50, maxAgeSeconds: 86400 })] }), 'GET');




